import React, { useState, useEffect, useRef } from 'react';
import { Mic, MicOff, Send, Pause, Play, Volume2, VolumeX, User, Bot, MessageSquare, FileText, BookOpen, Bookmark, Search, ZoomIn, ZoomOut, RotateCw, Download, Upload, Speaker, PlayCircle, Square, X, ChevronLeft, ChevronRight, Plus, Filter, Eye, Edit, Trash2, Award, Shield, Scale, Gavel, Book, Radio } from 'lucide-react';

interface Message {
  id: number;
  sender: 'user' | 'ai' | 'system';
  content: string;
  timestamp: Date;
  voiceUrl?: string; // URL for voice recording
  isPlaying?: boolean; // Whether voice is currently playing
}

interface Document {
  _id: string;
  name: string;
  type: 'contract' | 'evidence' | 'pleading' | 'correspondence' | 'case_file';
  pages: number;
  bookmarks?: BookmarkItem[];
  currentPage?: number;
}

interface BookmarkItem {
  id: string;
  page: number;
  label: string;
  note?: string;
}

interface VirtualBook {
  id: string;
  title: string;
  pages: number;
  currentPage: number;
  bookmarks: BookmarkItem[];
  content: string[];
}

interface EvidenceItem {
  id: string;
  name: string;
  type: 'digital' | 'physical' | 'document';
  description: string;
  dateAdded: string;
  fileSize: string;
  tags: string[];
  caseId: string;
  analysis?: {
    keyFindings: string[];
    relevance: string;
    reliability: string;
    notes: string;
  };
}

interface PaperworkTemplate {
  id: string;
  name: string;
  type: 'form' | 'document' | 'log';
  description: string;
  fields: string[];
}

interface Character {
  id: string;
  name: string;
  role: 'judge' | 'plaintiff' | 'defendant' | 'witness' | 'lawyer';
  avatar: string;
  bio: string;
  traits: string[];
  visualCues: {
    color: string;
    icon: string;
  };
}

const CourtroomSimulation: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputMessage, setInputMessage] = useState('');
  const [isRecording, setIsRecording] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [activeTab, setActiveTab] = useState<'chat' | 'documents' | 'notes' | 'evidence'>('chat');
  const [documents, setDocuments] = useState<Document[]>([]);
  const [virtualBooks, setVirtualBooks] = useState<VirtualBook[]>([]);
  const [selectedDocument, setSelectedDocument] = useState<Document | null>(null);
  const [selectedBook, setSelectedBook] = useState<VirtualBook | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [zoomLevel, setZoomLevel] = useState(100);
  const [bookmarks, setBookmarks] = useState<BookmarkItem[]>([]);
  const [isPlaying, setIsPlaying] = useState<number | null>(null); // ID of message currently playing
  const [mediaRecorder, setMediaRecorder] = useState<MediaRecorder | null>(null);
  const [audioChunks, setAudioChunks] = useState<Blob[]>([]);
  const [voicePlaying, setVoicePlaying] = useState<{[key: number]: boolean}>({});
  const [evidenceItems, setEvidenceItems] = useState<EvidenceItem[]>([]);
  const [paperworkTemplates, setPaperworkTemplates] = useState<PaperworkTemplate[]>([]);
  const [selectedEvidence, setSelectedEvidence] = useState<EvidenceItem | null>(null);
  const [showAddEvidence, setShowAddEvidence] = useState(false);
  const [characters, setCharacters] = useState<Character[]>([]);
  const [showCharacterPanel, setShowCharacterPanel] = useState(false);
  const [audioLevel, setAudioLevel] = useState(0); // For microphone input visualization
  const [recordingTime, setRecordingTime] = useState(0); // Recording duration in seconds
  const [isProcessing, setIsProcessing] = useState(false); // Processing state after recording
  const recordingIntervalRef = useRef<NodeJS.Timeout | null>(null);
  const audioLevelIntervalRef = useRef<NodeJS.Timeout | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);

  // Auto-scroll to bottom of messages
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  // Initialize media recorder for voice input
  useEffect(() => {
    const initMediaRecorder = async () => {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        mediaStreamRef.current = stream;
        
        const recorder = new MediaRecorder(stream);
        recorder.ondataavailable = (event) => {
          if (event.data.size > 0) {
            setAudioChunks((prev) => [...prev, event.data]);
          }
        };
        recorder.onstop = () => {
          // Process the recorded audio
          processAudioRecording();
        };
        setMediaRecorder(recorder);
      } catch (err) {
        console.error('Error accessing microphone:', err);
        // Show error to user
        setError('Microphone access denied. Please allow microphone access to use voice features.');
      }
    };

    initMediaRecorder();
    
    // Cleanup function
    return () => {
      if (mediaStreamRef.current) {
        mediaStreamRef.current.getTracks().forEach(track => track.stop());
      }
      if (recordingIntervalRef.current) {
        clearInterval(recordingIntervalRef.current);
      }
      if (audioLevelIntervalRef.current) {
        clearInterval(audioLevelIntervalRef.current);
      }
    };
  }, []);

  // Audio level monitoring
  useEffect(() => {
    if (isRecording && mediaStreamRef.current) {
      // Start monitoring audio levels
      const audioContext = new AudioContext();
      const analyser = audioContext.createAnalyser();
      const microphone = audioContext.createMediaStreamSource(mediaStreamRef.current);
      microphone.connect(analyser);
      
      analyser.fftSize = 256;
      const bufferLength = analyser.frequencyBinCount;
      const dataArray = new Uint8Array(bufferLength);
      
      const updateAudioLevel = () => {
        analyser.getByteFrequencyData(dataArray);
        let sum = 0;
        for (let i = 0; i < bufferLength; i++) {
          sum += dataArray[i];
        }
        const average = sum / bufferLength;
        // Normalize to 0-100
        setAudioLevel(Math.min(100, Math.max(0, Math.round(average * 2))));
      };
      
      audioLevelIntervalRef.current = setInterval(updateAudioLevel, 100);
    } else {
      // Stop monitoring
      if (audioLevelIntervalRef.current) {
        clearInterval(audioLevelIntervalRef.current);
        audioLevelIntervalRef.current = null;
      }
      setAudioLevel(0);
    }
    
    return () => {
      if (audioLevelIntervalRef.current) {
        clearInterval(audioLevelIntervalRef.current);
      }
    };
  }, [isRecording]);

