  const processAudioRecording = async () => {
    if (audioChunks.length === 0) return;
    
    setIsProcessing(true);
    
    try {
      // Combine audio chunks
      const audioBlob = new Blob(audioChunks, { type: 'audio/webm' });
      
      // In a real implementation, you would send this to your backend for speech-to-text conversion
      // For now, we'll simulate the process
      console.log('Audio recorded:', audioBlob);
      
      // Simulate processing delay
      await new Promise(resolve => setTimeout(resolve, 1500));
      
      // Convert to text (simulated)
      const simulatedText = "Based on the evidence presented, it's clear that there are inconsistencies in the inventory records that suggest possible internal fraud rather than theft by my client.";
      
      // Add to input message
      setInputMessage(simulatedText);
      
      // Reset audio chunks
      setAudioChunks([]);
      setIsProcessing(false);
      
      // Auto-send the message
      handleSendMessage();
    } catch (err) {
      console.error('Error processing audio:', err);
      setIsProcessing(false);
      setAudioChunks([]);
    }
  };

  const handleSendMessage = async () => {
    if (inputMessage.trim() === '') return;
    
    const newMessage: Message = {
      id: messages.length + 1,
      sender: 'user',
      content: inputMessage,
      timestamp: new Date()
    };
    
    setMessages([...messages, newMessage]);
    setInputMessage('');
    
    // Send message to backend and get AI response
    try {
      const response = await fetch('http://localhost:5000/api/courtroom/respond', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ message: inputMessage })
      });
      
      const data = await response.json();
      
      if (data.success) {
        // Convert timestamp string to Date object
        const aiMessage = {
          ...data.data,
          timestamp: new Date(data.data.timestamp),
          isPlaying: false
        };
        setMessages(prev => [...prev, aiMessage]);
      } else {
        // Fallback AI response if backend fails
        setTimeout(() => {
          const aiResponse: Message = {
            id: messages.length + 2,
            sender: 'ai',
            content: "Thank you for that statement, Counsel. The defendant would like to respond to your claims. Mr. Advocate for the defense, please present your counter-argument.",
            timestamp: new Date(),
            isPlaying: false
          };
          setMessages(prev => [...prev, aiResponse]);
        }, 2000);
      }
    } catch (err) {
      console.error('Error sending message:', err);
      // Fallback AI response if backend fails
      setTimeout(() => {
        const aiResponse: Message = {
          id: messages.length + 2,
          sender: 'ai',
          content: "Thank you for that statement, Counsel. The defendant would like to respond to your claims. Mr. Advocate for the defense, please present your counter-argument.",
